import React from "react"
import { Helmet } from "react-helmet";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

import LayoutMain from "../layout"
import ContentCard from "../components/ContentCard"

import config from "../app-config";

export default class SocialPage extends React.Component {

  getSocialAccounts(){
    /*
        <FontAwesomeIcon 
            color='white'
            transform='grow-24 right-5 down-4'
            icon={link.iconClassName}
            />
    */
    const socAcctList = [];
    config.socialLinks.forEach(link => {
      socAcctList.push({
        service: link.service,
        name: link.name,
        url: link.url,
        desc: link.description,
        icon: <FontAwesomeIcon 
                color={link.iconColor ? link.iconColor : 'white' }
                transform='grow-16' // right-5 down-4'
                icon={link.iconClassName}
              />
      })
    });

    return socAcctList;
  }

  render() {
    const socialAccounts = this.getSocialAccounts();
    return (
      <div>
        <Helmet>
          <title>Social Media | Amperture Engineering</title>
        </Helmet>
        <LayoutMain>
          <div className='md-grid'>
              {socialAccounts.map(acct => (
                <ContentCard
                  className='md-cell'
                  titleText={acct.service}
                  subtitleText=<a href="{acct.url}">{acct.name}</a>
                  avatar={acct.icon}
                >
                  <p>{acct.desc}</p>
                </ContentCard>
              ))}
          </div>
        </LayoutMain>
      </div>
    )
  }
}
